function ukiyo_translate_english_html( $html ) {
    if ( ! is_string( $html ) || '' === $html || ! ukiyo_is_english_request() ) {
        return $html;
    }

    $replacements = ukiyo_get_english_text_replacements();
    uksort(
        $replacements,
        static function ( $left, $right ) {
            return strlen( $right ) <=> strlen( $left );
        }
    );

	    $html = strtr( $html, $replacements );

	    $regex_replacements = [
	        '/Política de\s*<span([^>]*)>privacidad<\/span>/u' => 'Privacy <span$1>policy</span>',
	        '/Política de\s*<span([^>]*)>cookies<\/span>/u' => 'Cookie <span$1>policy</span>',
	        // CTA del page-reviews2 con <br/> entre líneas.
	        '/Tu aventura<br\/?>\s*empieza\s*<em>aquí\.<\/em>/u' => 'Your adventure<br/>starts <em>here.</em>',
	        // Sec-head del page-reviews2 con <br/>.
	        '/Lo que\s*<em>cuentan<\/em><br\/?>\s*quienes ya viajaron\./u' => 'What <em>they tell</em><br/>those who have already travelled.',
	        // Featured h2 del blog (home.php) y del .ukiyo-blog featured: "Por X · Fecha · Y min de lectura"
	        '/Por\s*<strong>([^<]+)<\/strong>/u' => 'By <strong>$1</strong>',
	        // Card de related del single-viaje_autor: <small>Desde</small>.
	        '/<small>Desde<\/small>/u' => '<small>From</small>',
	        // Helper destination v2 — chips de hosts.
	        '/Conoce a nuestros<br\/?>\s*<em>anfitriones\.<\/em>/u' => 'Meet our<br/><em>hosts.</em>',
	        // Helper v2 — "Lo que hace única/único a X" (con o sin <br/> y sus variantes).
	        '/Lo que hace\s*<em>única<\/em><br\s*\/?>\s*a\s+([A-ZÁÉÍÓÚÑa-záéíóúñ ]+)\./u' => 'What makes <em>$1</em><br/>unique.',
	        '/Lo que hace\s*<em>único<\/em><br\s*\/?>\s*a\s+([A-ZÁÉÍÓÚÑa-záéíóúñ ]+)\./u' => 'What makes <em>$1</em><br/>unique.',
	        // Y la variante simple sin <br/> (en line breaks distintos).
	        '/Lo que hace\s*<em>única<\/em>\s+a\s+([A-ZÁÉÍÓÚÑa-záéíóúñ ]+)\./u' => 'What makes <em>$1</em> unique.',
	        '/Lo que hace\s*<em>único<\/em>\s+a\s+([A-ZÁÉÍÓÚÑa-záéíóúñ ]+)\./u' => 'What makes <em>$1</em> unique.',
	        // Helper v2 — "Ocho/Doce lugares que marcan la ruta." con cualquier variante de <br/>.
	        '/(\w+) lugares<br\s*\/?>\s*que\s*<em>marcan<\/em>\s*la ruta\./u' => '$1 places<br/>that <em>shape</em> the route.',
	        // Helper v2 — CTA final "¿Listo para vivir <em>X</em>?" (acepta <br>, <br/>, <br />)
	        '/¿Listo para vivir<br\s*\/?>\s*<em>([^<]+)<\/em>/u' => 'Ready to experience<br/><em>$1</em>',
	        // Variante sin <br/>: "¿Listo para vivir <em>X</em>?"
	        '/¿Listo para vivir\s+<em>([^<]+)<\/em>/u' => 'Ready to experience <em>$1</em>',
	        // Y la variante donde "¿Listo para vivir" aparece solo (sin em justo después).
	        '/¿Listo para vivir(?=[\s<])/u' => 'Ready to experience',
	        // Blog featured artículo: "Empieza por el tipo de viaje o por <em>destino.</em>"
	        '/Empieza por el tipo de viaje o por\s*<em>destino\.<\/em>/u' => 'Start by trip type or by <em>destination.</em>',
	        // Blog hero title.
	        '/Blog de viajes a medida<br\/?>\s*y\s*<em>guías de destino\.<\/em>/u' => 'Tailor-made travel blog<br/>and <em>destination guides.</em>',
	        // Reviews hero title.
	        '/Historias de nuestros\s*<em>viajeros\.<\/em>/u' => 'Stories from our <em>travellers.</em>',
	        // Footer tag.
	        '/Viajes auténticos, sostenibles y creados a tu medida\.\s*<em>Pisados antes<\/em> por nosotros\./u' => 'Authentic, sustainable, tailor-made trips. <em>Walked first</em> by us.',
	        // Blog featured CTA "¿Quieres preparar tu viaje <em>con ayuda?</em>"
	        '/¿Quieres preparar tu viaje<br\/?>\s*<em>con ayuda\?<\/em>/u' => 'Want to prepare your trip<br/><em>with help?</em>',
	        // Blog últimas guías.
	        '/Últimas\s*<em>guías y crónicas\.<\/em>/u' => 'Latest <em>guides and chronicles.</em>',
	        // CTA primarios "Diseñar mi viaje a <destino>" — pillar variantes con espacios.
	        '/Diseñar mi viaje a\s+(Costa Rica|Indonesia|Italia|Italy|Colombia|Marruecos|Morocco|Lanzarote|Sierra de Andújar)/u' => 'Design my trip to $1',
	        '/Empezar mi viaje a\s+(Costa Rica|Indonesia|Italia|Italy|Colombia|Marruecos|Morocco|Lanzarote)/u' => 'Start my trip to $1',
	        // Normalizamos los nombres de país que ya están traducidos en otro paso.
	        '/Italia/u' => 'Italy',
	        '/Marruecos/u' => 'Morocco',
	        '/Durante años viajamos por separado, aprendiendo, descubriendo y viviendo experiencias que, sin saberlo, nos estaban llevando exactamente al mismo lugar:\s*<strong>crear algo juntos<\/strong>\./u' => 'For years we traveled separately, learning, discovering and living experiences that, without knowing it, were leading us to the same place: <strong>creating something together</strong>.',
	        '/<strong>Bonus 48 h:<\/strong>\s*si reservas durante la llamada, recibes el\s*<strong>Boceto de Viaje<\/strong>\s*en 48 h — incluido\./u' => '<strong>48 h bonus:</strong> if you book during the call, you receive the <strong>Trip Sketch</strong> within 48 h, included.',
	        '/<span><b>30 min<\/b>duración<\/span>/u' => '<span><b>30 min</b>duration</span>',
	        '/<span><b>Gratis<\/b>sin compromiso<\/span>/u' => '<span><b>Free</b>no commitment</span>',
	        // 'persona'/'personas' with word boundaries — safe in URLs (won't match inside 'personalizados').
	        '/\bpersonas\b/u' => 'people',
	        '/\bpersona\b/u' => 'person',
	    ];

	    return preg_replace( array_keys( $regex_replacements ), array_values( $regex_replacements ), $html );
	}

function ukiyo_start_english_translation_buffer() {
    if ( is_admin() || is_feed() || is_preview() || wp_doing_ajax() || wp_is_json_request() || ! ukiyo_is_english_request() ) {
        return;
    }

    ob_start( 'ukiyo_translate_english_html' );
}
add_action( 'template_redirect', 'ukiyo_start_english_translation_buffer', 19 );

function ukiyo_english_canonical_url( $canonical ) {
    if ( ! ukiyo_is_english_request() ) {
        return $canonical;
    }

    if ( is_front_page() && function_exists( 'pll_home_url' ) ) {
        return pll_home_url( 'en' );
    }

    if ( is_singular() ) {
        return get_permalink( get_queried_object_id() );
    }

    return $canonical;
}
add_filter( 'rank_math/frontend/canonical', 'ukiyo_english_canonical_url' );
add_filter( 'wpseo_canonical', 'ukiyo_english_canonical_url' );
